import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"

describe("values source", () => {
  it("should not abort when abort is false/null and array is provided", (done) => {
    const array = [10, 20, 30];
    const source = values(array);

    // In the original code, the early abort check only triggers when abort is truthy
    // In the mutated code, `if(true)` always calls abortCb, so we never get values
    let callCount = 0;

    source(false, (err: any, val: any) => {
      callCount++;
      // Should receive first value without error
      expect(err).toBeNull();
      expect(val).toBe(10);
      expect(callCount).toBe(1);
      done();
    });
  });
});
```

Looking at the mutation more carefully:

- Original: `if(abort) return abortCb(cb, abort, onAbort)` - this is an early check before array processing
- Mutated: `if(true) return abortCb(cb, abort, onAbort)` - this always aborts

The key is that this early check happens when `array` is provided (not null/undefined). In the mutated code, calling the source function with a non-array object (which triggers the `Object.keys` path) or even a regular array will always call `abortCb` instead of returning values.

```typescript
import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"

describe("values source", () => {
  it("should call callback with null error and value when reading from array with no abort", (done) => {
    const source = values([42, 43, 44]);

    // Pass abort=null (falsy) - original code skips the early abort check and proceeds normally
    // Mutated code always calls abortCb regardless, so cb would be called with an error
    source(null, (err: any, val: any) => {
      if (err) {
        // In mutated code, abortCb is called with abort=null, which calls cb(null) - end of stream
        // So we need to check that we actually got a value
        done(new Error(`Expected a value but got err=${err}`));
      } else {
        expect(val).toBe(42);
        done();
      }
    });
  });
});
```

Wait, let me reconsider what `abortCb(cb, null, onAbort)` does. If abort is null/falsy, abortCb likely calls `cb(null)` signaling end of stream. Let me write a test that checks we get a value (not end of stream):

```typescript
import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"

describe("values source", () => {
  it("should return actual values when reading with abort=null from a non-empty array", (done) => {
    const source = values([42, 43, 44]);

    source(null, (err: any, val: any) => {
      // Original: err=null, val=42 (first element)
      // Mutated: abortCb(cb, null, onAbort) is called, which signals end-of-stream (err=true or err=null with no val)
      expect(err).toBeNull();
      expect(val).toBe(42);
      done();
    });
  });
});
```

Let me look more carefully at where the placeholder is in the code. The early abort check is placed BEFORE the `Array.isArray` check. So it's called on the initial invocation of the outer function... wait, no. Let me re-read.

The structure is:
1. `if(!array)` - return empty function
2. `<PLACEHOLDER>` - early abort check  
3. `if(!Array.isArray(array))` - convert object to array
4. `var i = 0`
5. `return function(abort, cb) {...}` - the actual source function

So the placeholder is in the **setup phase** (outer function), not inside the returned function. The `abort` and `cb` parameters at this level would be `undefined`. With `if(true)`, it always calls `abortCb(cb, abort, onAbort)` where `cb` is `undefined`.

```typescript
import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"

describe("values source", () => {
  it("should return a function when called with an array", () => {
    // In original code, the outer function returns the inner source function
    // In mutated code, if(true) calls abortCb(cb, abort, onAbort) where cb=undefined (outer params)
    // and then returns undefined instead of the inner function
    const source = values([1, 2, 3]);

    expect(typeof source).toBe("function");
  });
});
```

Let me re-read the code structure very carefully:

```js
module.exports = function values (array, onAbort) {
  if(!array) return function (abort, cb) {}
  <PLACEHOLDER>  // if(abort) return abortCb(cb, abort, onAbort)
  if(!Array.isArray(array)) ...
  var i = 0
  return function (abort, cb) { ... }
}
```

The `values` function takes `(array, onAbort)`. The placeholder uses `abort` - but there's no `abort` parameter in the outer function! So in the original, `abort` is `undefined` (falsy), so `if(abort)` never triggers. In the mutated code, `if(true)` always triggers, calling `abortCb(cb, abort, onAbort)` where `cb` is also `undefined`. This would cause an error or return `undefined` instead of the inner function.

```typescript
import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"

describe("values source", () => {
  it("should return a callable source function that yields array values", (done) => {
    // In mutated code, abortCb(undefined, undefined, undefined) is called during setup
    // which may throw or cause the function to not return properly
    let source: any;
    expect(() => {
      source = values([1, 2, 3]);
    }).not.toThrow();

    expect(source).toBeDefined();

    source(null, (err: any, val: any) => {
      expect(err).toBeNull();
      expect(val).toBe(1);
      done();
    });
  });
});
```

Let me look at what `abortCb` actually does when called with `undefined` arguments, and trace through more carefully.

The `abortCb` utility likely calls `cb(abort)`. When called as `abortCb(undefined, undefined, undefined)`, it would try to call `undefined()` which throws. But the test passes on mutated code, so maybe `abortCb` handles undefined gracefully.

The key insight: after `abortCb` is called, the function **returns** early, so `var i = 0` and the `return function(...)` are never reached. So `values([1,2,3])` returns `undefined` in mutated code.

```typescript
import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"
import abortCb from "../../../../../../../../../../../subject_repositories/pull-stream/util/abort-cb.js"

describe("values source", () => {
  it("should return undefined in mutated code because abortCb causes early return", (done) => {
    const source = values([1, 2, 3]);

    // If mutated, source is undefined because abortCb returns early
    // If original, source is a function
    source(null, (err: any, val: any) => {
      expect(err).toBeNull();
      expect(val).toBe(1);
      done();
    });
  });
});
```

Wait, I keep writing the same test. Let me check what `abortCb` returns when cb is undefined - it likely just returns without calling cb. So `values([1,2,3])` returns `undefined`. Then calling `undefined(null, cb)` would throw `TypeError`. Let me test for that:

```typescript
import values from "../../../../../../../../../../../subject_repositories/pull-stream/sources/values.js"

describe("values source", () => {
  it("should return a function (not undefined) when given a valid array", () => {
    const result = values([1, 2, 3]);
    // In mutated code: if(true) return abortCb(cb, abort, onAbort) 
    // abortCb returns undefined, so values() returns undefined
    // In original code: if(abort) is false, so we proceed to return the inner function
    expect(result).not.toBeUndefined();
    expect(typeof result).toBe("function");
  });
});
```
